def two_sum_ii(numbers, target):
    lo, hi = 0, len(numbers) - 1
    while lo < hi:
        s = numbers[lo] + numbers[hi]
        if s == target:
            return [lo + 1, hi + 1]
        if s < target:
            lo += 1
        else:
            hi -= 1
    return []

code.javascript:
function twoSumII(numbers, target) {
  let lo = 0;
  let hi = numbers.length - 1;
  while (lo < hi) {
    const s = numbers[lo] + numbers[hi];
    if (s === target) {
      return [lo + 1, hi + 1];
    }
    if (s < target) {
      lo++;
    } else {
      hi--;
    }
  }
  return [];
}

